step.script:
echo "Collecting statistics at $(date)"

# Create stats file
STATS_FILE="/var/lib/dagu/data/table_stats_$(date +%Y%m%d_%H%M%S).json"
echo '{
  "timestamp": "'$(date -Iseconds)'",
  "connection": "'${CONNECTION_ID}'",
  "tables": '${ALL_TABLES}'
}' | jq '.' > ${STATS_FILE}

echo "Statistics saved to: ${STATS_FILE}"
cat ${STATS_FILE}

DASHBOARD_FILE="/var/lib/dagu/data/dashboard_latest.json"

echo '{
  "last_updated": "'$(date -Iseconds)'",
  "connection": "'${CONNECTION_ID}'",
  "summary": {
    "total_tables": '$(echo "${ALL_TABLES}" | jq '.total_tables')',
    "checks_passed": '$(echo "${CRITICAL_CHECKS}" | jq '.statistics.passed')',
    "checks_failed": '$(echo "${CRITICAL_CHECKS}" | jq '.statistics.failed')',
    "checks_total": '$(echo "${CRITICAL_CHECKS}" | jq '.statistics.total_expectations')'
  },
  "critical_checks": '${CRITICAL_CHECKS}',
  "all_tables": '${ALL_TABLES}'
}' | jq '.' > ${DASHBOARD_FILE}

echo "📊 Dashboard data updated: ${DASHBOARD_FILE}"
cat ${DASHBOARD_FILE} | jq '.summary'
